// WF03 Prospector v2.0 - Parse webhook input
// Input formats:
//   1. Frontend /api/prospect: { linea, empresas: ["name1","name2"], pais?, paises?:[], tier?, contactos_por_empresa }
//   2. WF02 trigger:          { empresa, pais, linea_negocio, tier, company_domain, score_* }
//   3. WF02 uppercase:        { "COMPANY NAME", "PAÍS", "LÍNEA DE NEGOCIO", "TIER", ... }
const raw = $input.all()[0].json;
const body = raw.body || raw;

let empresas = [];

if (body.empresas && Array.isArray(body.empresas)) {
  empresas = body.empresas.map(e => {
    if (typeof e === 'string') {
      return {
        empresa:        e,
        pais:           body.pais || 'Colombia',
        paises:         body.paises || [],
        linea_negocio:  body.linea || body.linea_negocio || '',
        tier:           body.tier || 'MONITOREO',
        company_domain: body.company_domain || '',
        score_calificacion: 0,
        score_radar:    0,
        composite_score: 0,
      };
    }
    return e;
  });
} else if (body.empresa || body['COMPANY NAME']) {
  empresas = [body];
}

if (!empresas.length) {
  throw new Error('WF03: No empresas found. Expected { empresas:[...] } or { empresa: "..." }');
}

return empresas.flatMap(e => {
  const tier = (e.tier_calculado || e.tier || e['TIER'] || 'MONITOREO').toUpperCase();
  // v2: ORO=5, PLATA=4, MONITOREO=3, else skip
  const maxContacts = tier === 'ORO' ? 5 : tier === 'PLATA' ? 4 : tier === 'MONITOREO' ? 3 : 0;
  if (maxContacts === 0) return [];

  const empresa     = e.empresa || e.company_name || e['COMPANY NAME'] || '';
  const paisBase    = e.pais || e['PAÍS'] || 'Colombia';
  const linea       = e.linea_negocio || e.linea || e['LÍNEA DE NEGOCIO'] || e['LINEA DE NEGOCIO'] || '';
  const domain      = e.company_domain || e['DOMINIO'] || '';
  const fecha       = new Date().toISOString().split('T')[0];

  // If paises array provided → one item per country
  const paises = (e.paises && e.paises.length > 0) ? e.paises : [paisBase];

  return paises.map(pais => ({ json: {
    empresa, pais, linea_negocio: linea, tier,
    company_domain: domain,
    score_calificacion: e.score_calificacion || e['SCORE_CAL']  || 0,
    score_radar:        e.score_radar        || e['SCORE_RADAR'] || 0,
    composite_score:    e.composite_score    || e['COMPOSITE']   || 0,
    max_contacts: maxContacts,
    fecha_prospeccion: fecha,
    grupo_empresarial: e.grupo_empresarial || '',
    es_multinacional: paises.length > 1,
  }}));
}).filter(Boolean);

const e = $input.all()[0].json;
const linea = (e.linea_negocio || '').toLowerCase()
  .normalize('NFD').replace(/[\u0300-\u036f]/g, '');

// v2.0: 6 líneas with curated titles per line
// Sources: JobTitles_PorLineaNegocio.xlsx (ALTA priority)
const TITLES = {
  BHS: [
    'Chief Executive Officer','CEO','Chief Operating Officer','COO',
    'Chief Technical Officer','Chief Infrastructure Officer',
    'Director General Aeropuerto','Director de Infraestructura Aeropuerto',
    'Director de Operaciones Aeropuerto','Director de Ingeniería Aeropuerto',
    'Director de Mantenimiento','Director de Proyectos Estratégicos',
    'Vice President Airport Operations','Vice President Infrastructure',
    'Airport Operations Manager','Airport Infrastructure Manager',
    'Airport Engineering Manager','Airport Technical Manager',
    'Baggage Handling System Manager','BHS Manager',
    'Cargo Terminal Manager','Air Cargo Operations Manager',
    'Airport Facilities Manager','Airport Maintenance Manager',
    'Gerente de Infraestructura Aeropuerto','Gerente de Operaciones Aeropuerto',
    'Gerente de Proyectos Aeropuerto','Gerente BHS',
    'Managing Director','Country Manager','Operations Director'
  ],
  CARTON_PAPEL: [
    'Gerente General','Director General','Dueño','Owner',
    'Director de Proyectos','Director Técnico','Director de Compras',
    'Director de Operaciones','Gerente de Planta','Superintendente de Planta',
    'Gerente de Mantenimiento','Project Manager','Gerente de Proyectos',
    'Gerente de Compras','Plant Manager','Manufacturing Director'
  ],
  INTRALOGISTICA: [
    'Chief Operations Officer','COO','CEO','VP Operations',
    'Operations Director','Plant Director','Manufacturing Director',
    'Supply Chain Director','Director de Operaciones','Director de Planta',
    'Director de Manufactura','Operations Manager','Plant Manager',
    'Manufacturing Manager','Engineering Manager','Project Manager',
    'Capital Projects Manager','Supply Chain Manager','Logistics Manager',
    'Intralogistics Manager','Automation Manager','Gerente de Planta',
    'Gerente de Operaciones','Gerente de Producción','Gerente de Logística',
    'Gerente de Proyectos','Gerente de Supply Chain','Gerente General'
  ],
  FINAL_LINEA: [
    'CEO','COO','Gerente General','Director General',
    'Director de Operaciones','Director de Supply Chain',
    'Director de Manufactura','Director de Producción','Director de Logística',
    'Plant Manager','Gerente de Planta','Operations Manager','Gerente de Operaciones',
    'Supply Chain Manager','Gerente de Supply Chain',
    'Manufacturing Manager','Gerente de Manufactura',
    'Logistics Manager','Gerente de Logística',
    'Packaging Manager','Gerente de Empaque',
    'Head of Operations','Head of Supply Chain','Country Manager'
  ],
  MOTOS: [
    'CEO','Gerente General','Director General',
    'Director de Manufactura','Director de Operaciones','Director de Producción',
    'Plant Manager','Gerente de Planta',
    'Manufacturing Manager','Gerente de Manufactura',
    'Production Manager','Gerente de Producción',
    'Assembly Manager','Gerente de Ensamble',
    'Operations Manager','Gerente de Operaciones'
  ],
  SOLUMAT: [
    'CEO','Gerente General','Director General',
    'Director de Operaciones','Director de Manufactura','Director de Producción',
    'Plant Manager','Gerente de Planta',
    'Manufacturing Manager','Gerente de Manufactura',
    'Process Manager','Gerente de Procesos',
    'Operations Manager','Gerente de Operaciones',
    'Production Manager','Gerente de Producción'
  ]
};

// Map linea_negocio string to 6 canonical keys
let lineaKey = 'INTRALOGISTICA'; // default
if (linea.includes('bhs') || linea.includes('aeropuerto') || linea.includes('cargo') || linea.includes('uld')) {
  lineaKey = 'BHS';
} else if (linea.includes('cart') || linea.includes('corrugado') || linea.includes('papel')) {
  lineaKey = 'CARTON_PAPEL';
} else if (linea.includes('final') || linea.includes('alimento') || linea.includes('bebida')) {
  lineaKey = 'FINAL_LINEA';
} else if (linea.includes('moto')) {
  lineaKey = 'MOTOS';
} else if (linea.includes('solumat') || linea.includes('plastico') || linea.includes('material')) {
  lineaKey = 'SOLUMAT';
}

const titles = TITLES[lineaKey] || TITLES.INTRALOGISTICA;
// per_page: get more candidates than max_contacts to allow scoring; cap at 25
const perPage = Math.min(25, (e.max_contacts || 3) * 4);

const searchBody = {
  page: 1,
  per_page: perPage,
  person_seniorities: ['c_suite', 'vp', 'director', 'manager'],
  person_titles: titles,
};

// Prefer domain search over name search (more precise)
if (e.company_domain) {
  searchBody.q_organization_domains_list = [e.company_domain];
} else {
  searchBody.q_organization_name = e.empresa;
}

// Add country filter — critical for international companies
const COUNTRY_MAP = {
  'colombia': 'Colombia', 'mexico': 'Mexico', 'chile': 'Chile',
  'peru': 'Peru', 'argentina': 'Argentina', 'brasil': 'Brazil',
  'brazil': 'Brazil', 'guatemala': 'Guatemala', 'costa rica': 'Costa Rica',
  'ecuador': 'Ecuador', 'panama': 'Panama'
};
const paisNorm = (e.pais || '').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
const countryMapped = COUNTRY_MAP[paisNorm] || e.pais;
if (countryMapped) {
  searchBody.person_locations = [countryMapped];
}

return [{ json: { ...e, apollo_search_body: searchBody, _linea_key: lineaKey, _titles_count: titles.length } }];

const apolloResp = $input.all()[0].json;
const ctx = $('Code: Build Apollo Query').first().json;

// v2: handle rate limit (429) — mark for retry
const statusCode = apolloResp.statusCode || apolloResp.status || 200;
if (statusCode === 429) {
  return [{ json: { ...ctx, apollo_response: null, _rate_limited: true } }];
}
return [{ json: { ...ctx, apollo_response: apolloResp, _rate_limited: false } }];

// v2.0: Score and select top N contacts with Matec seniority hierarchy
const ctx = $input.all()[0].json;
const resp = ctx.apollo_response || {};
const raw = resp.people || resp.contacts || resp.results || resp.data || [];
const maxContacts = ctx.max_contacts || 3;

// Matec seniority scoring: C-LEVEL > DIRECTOR > GERENTE > JEFE
const seniorityScore = { c_suite: 5, vp: 4, director: 3, manager: 2, individual_contributor: 1 };

// Classify nivel exactly as Matec standard
function classifyNivel(title, seniority) {
  const t = (title || '').toLowerCase();
  const s = (seniority || '').toLowerCase();
  const clevel = ['chief executive','chief operations','chief operating','gerente general',
    'director general','managing director','country general manager','country manager'];
  if (clevel.some(x => t.includes(x))) return 'C-LEVEL';
  if (t.startsWith('ceo') || t.includes(' ceo') || t.startsWith('coo') || t.includes(' coo')) return 'C-LEVEL';
  if (s === 'c_suite') return 'C-LEVEL';
  if (t.includes('director') || t.includes('vice president') || t.includes(' vp ') || s === 'vp') return 'DIRECTOR';
  if (t.includes('gerente') || t.includes('manager') || t.includes('head of') || s === 'director' || s === 'manager') return 'GERENTE';
  return 'JEFE';
}

const NIVEL_ORDER = { 'C-LEVEL': 4, 'DIRECTOR': 3, 'GERENTE': 2, 'JEFE': 1 };

const scored = raw.map(p => {
  const nivel = classifyNivel(p.title, p.seniority);
  const hasEmail = !!(p.email || p.has_email || p.work_email);
  const hasLinkedin = !!(p.linkedin_url);
  return {
    ...p, _nivel: nivel,
    _priority: (NIVEL_ORDER[nivel] || 0) * 10 + (hasEmail ? 3 : 0) + (hasLinkedin ? 1 : 0)
  };
}).sort((a, b) => b._priority - a._priority);

// Select top maxContacts — ensure at least 1 per seniority level if available
const selected = scored.slice(0, maxContacts);

if (!selected.length) {
  return [{ json: { ...ctx, contacts_found: 0, contacts: [], prospection_status: 'NO_CONTACTS_FOUND' } }];
}

const contacts = selected.map(p => {
  const phones = p.phone_numbers || [];
  const nivel  = p._nivel;
  return {
    nombre:        p.first_name || '',
    apellido:      p.last_name || p.last_name_obfuscated || '',
    cargo:         p.title || p.headline || '',
    nivel,
    email:         p.email || p.work_email || '',
    email_status:  p.email_status || (p.email ? 'verified' : (p.has_email ? 'available' : 'not_found')),
    linkedin:      p.linkedin_url || '',
    tel_empresa:   (p.organization && (p.organization.phone || (p.organization.primary_phone && p.organization.primary_phone.number))) || '',
    tel_directo:   (phones.find(t => t.type === 'work_direct' || t.type === 'direct') || {}).sanitized_number || '',
    tel_movil:     (phones.find(t => t.type === 'mobile') || {}).sanitized_number || '',
    grupo:         (p.organization && p.organization.parent_organization && p.organization.parent_organization.name) || ctx.grupo_empresarial || '',
    ciudad:        p.city || (p.organization && p.organization.city) || '',
    apollo_id:     p.id || '',
    has_email:     !!(p.email || p.has_email),
    has_linkedin:  !!(p.linkedin_url),
  };
});

return [{ json: { ...ctx, contacts_found: contacts.length, contacts, prospection_status: 'CONTACTS_FOUND' } }];

const data = $input.all()[0].json;
return [{ json: {
  ID:              data.empresa,
  Empresa_Dominio: data.company_domain || data.empresa,
  Sub_Linea:       data.linea_negocio,
  Pais:            data.pais,
  Estado_Ciudad:   '',
  Dominio:         data.company_domain || '',
  Razon:           'Apollo no devolvió contactos para los títulos buscados',
  Re_escanear:     'Si',
  Fecha:           data.fecha_prospeccion,
  Tier:            data.tier,
}}];
